// ==================== UI РЕНДЕРИНГ (100% ВСЕ ЭКРАНЫ) ====================
import { AppState, EventBus, updateCoins, updateSolved, getAchievements, openChest,
         updatePetHunger, updatePetHappiness, updatePetEnergy, petGoToSleep, petWakeUp, setTheme } from './state.js';
import { Screens, navigateTo } from './router.js';
