// ==================== ВЫБОР РЕБЁНКА ====================
export function renderChildSelect(app) {
    const profiles = loadProfiles();
    app.innerHTML = `<div class="card child-select-card"><div class="child-select-header"><div class="robot-welcome"><div class="robot-avatar">🤖</div><div class="robot-message"><h2>Привет!</h2><p>Кто будет играть?</p></div></div></div><div class="child-list" id="childList">${profiles.map(p=>`<div class="child-card" data-child-id="${p.id}"><div class="child-avatar">🧑‍🎓</div><div class="child-name">${p.name}</div><div class="child-info">${p.password?'🔒':'🔓'} ${new Date(p.createdAt).toLocaleDateString()}</div></div>`).join('')}</div><div class="child-actions"><button id="addNewChildBtn" class="btn-secondary">➕ Новый ученик</button><button id="parentAccessBtn" class="btn-secondary">🔐 Родителям</button></div></div>`;
    document.querySelectorAll('.child-card').forEach(card=>{card.onclick=()=>{const id=card.dataset.childId;const p=profiles.find(x=>x.id===id);if(!p)return;if(p.password){showPasswordPrompt(id,p.name)}else{AppState.currentChild=p;import('./storage.js').then(m=>m.loadState(id));navigateTo(Screens.MAIN)}}});
    document.getElementById('addNewChildBtn').onclick=()=>showAddChildDialog();
    document.getElementById('parentAccessBtn').onclick=()=>showParentLogin();
}
function showPasswordPrompt(childId,childName){const c=document.getElementById('modal-container');const m=document.createElement('div');m.className='modal-overlay';m.innerHTML=`<div class="modal-card"><h3>🔐 Введи пароль</h3><p>Профиль: <strong>${childName}</strong></p><input type="password" id="childPasswordInput" placeholder="Пароль" autofocus><div class="modal-buttons"><button id="submitPasswordBtn">✅ Войти</button><button id="cancelPasswordBtn" class="btn-secondary">Отмена</button></div></div>`;c.appendChild(m);document.getElementById('submitPasswordBtn').onclick=()=>{if(verifyChildPassword(childId,document.getElementById('childPasswordInput').value)){const p=loadProfiles().find(x=>x.id===childId);AppState.currentChild=p;import('./storage.js').then(m2=>m2.loadState(childId));m.remove();navigateTo(Screens.MAIN)}else showNotification('❌ Неверный пароль','error')};document.getElementById('cancelPasswordBtn').onclick=()=>m.remove();m.addEventListener('click',e=>{if(e.target===m)m.remove()})}
function showAddChildDialog(){const c=document.getElementById('modal-container');const m=document.createElement('div');m.className='modal-overlay';m.innerHTML=`<div class="modal-card"><h3>👶 Новый ученик</h3><input type="text" id="newChildName" placeholder="Имя" autofocus><input type="password" id="newChildPassword" placeholder="Пароль (необязательно)"><div class="modal-buttons"><button id="createChildBtn">✅ Создать</button><button id="cancelChildBtn" class="btn-secondary">Отмена</button></div></div>`;c.appendChild(m);document.getElementById('createChildBtn').onclick=()=>{const n=document.getElementById('newChildName').value.trim();if(!n){showNotification('❌ Введи имя!','error');return}if(loadProfiles().some(x=>x.name===n)){showNotification('❌ Такое имя уже есть!','error');return}addProfile(n,document.getElementById('newChildPassword').value);m.remove();showNotification(`✅ ${n} добавлен!`,'success');renderChildSelect(document.getElementById('app'))};document.getElementById('cancelChildBtn').onclick=()=>m.remove();m.addEventListener('click',e=>{if(e.target===m)m.remove()})}
function showParentLogin(){const c=document.getElementById('modal-container');const m=document.createElement('div');m.className='modal-overlay';m.innerHTML=`<div class="modal-card"><h3>🔐 Доступ для родителей</h3><p style="text-align:center;color:#888;">По умолчанию: 0000</p><input type="password" id="parentPasswordInput" placeholder="Мастер-пароль" autofocus><div class="modal-buttons"><button id="submitParentPasswordBtn">✅ Войти</button><button id="cancelParentBtn" class="btn-secondary">Отмена</button></div></div>`;c.appendChild(m);document.getElementById('submitParentPasswordBtn').onclick=()=>{if(document.getElementById('parentPasswordInput').value===AppState.parentControl.password){m.remove();navigateTo(Screens.PARENT)}else showNotification('❌ Неверный пароль','error')};document.getElementById('cancelParentBtn').onclick=()=>m.remove();m.addEventListener('click',e=>{if(e.target===m)m.remove()})}

// ==================== ГЛАВНОЕ МЕНЮ ====================
export function renderMainMenu(app) {
    const pet = AppState.pet || { name: 'Мурка', emoji: '🐱', hunger: 100, happiness: 100, energy: 100 };
    const actions = { lessons: Screens.SUBJECT_SELECTION, arcade: Screens.ARCADE_HUB, pet: Screens.PET_MODULE, shop: Screens.SHOP, achievements: Screens.ACHIEVEMENTS, daily: Screens.DAILY_TASKS, reference: Screens.REFERENCE, settings: Screens.SETTINGS, parent: Screens.PARENT, switchChild: Screens.CHILD_SELECT };
    const menuItems = [{ action: 'lessons', emoji: '📚', name: 'УРОКИ' },{ action: 'arcade', emoji: '🎮', name: 'ИГРОТЕКА' },{ action: 'pet', emoji: '🐾', name: 'ПИТОМЕЦ' },{ action: 'shop', emoji: '🛒', name: 'МАГАЗИН' },{ action: 'achievements', emoji: '🏆', name: 'НАГРАДЫ' },{ action: 'daily', emoji: '📅', name: 'ЗАДАНИЯ' },{ action: 'reference', emoji: '📖', name: 'СПРАВОЧНИК' },{ action: 'settings', emoji: '⚙️', name: 'НАСТРОЙКИ' },{ action: 'parent', emoji: '👨‍👩‍👧', name: 'РОДИТЕЛЯМ' },{ action: 'switchChild', emoji: '👤', name: 'СМЕНИТЬ' }];
    app.innerHTML = `<div class="card main-menu-card"><div class="top-panel"><div class="coins-display"><span>🪙</span><span id="globalCoins">${AppState.coins}</span></div><div class="coins-display"><span>📚</span><span id="globalSolved">${AppState.totalSolved}</span></div><div class="coins-display"><span>🔥</span><span id="globalStreak">${AppState.streak}</span></div>${AppState.chests.available>0?`<div class="coins-display chests-badge" id="chestsBadge" style="background:linear-gradient(135deg,#ffd700,#ffb347);cursor:pointer;"><span>🎁</span><span>${AppState.chests.available}</span></div>`:''}</div><div class="menu-header"><div class="robot-section"><div class="robot-avatar">🤖</div><div class="robot-message">Привет, ${AppState.currentChild?.name||'Ученик'}!<br>Чем займёмся?</div></div><div class="home-pet-widget" id="homePetWidget"><div class="home-pet-emoji">${pet.emoji||'🐱'}</div><div class="home-pet-bubble" id="homePetBubble" style="display:none;"></div><div class="home-pet-name">${pet.name}</div><div class="pet-status-mini"><span style="color:${pet.hunger<30?'#e74c3c':'inherit'}">🍖</span><span style="color:${pet.happiness<30?'#ff9800':'inherit'}">😊</span><span style="color:${pet.energy<30?'#2196f3':'inherit'}">⚡</span></div></div></div><div class="menu-grid">${menuItems.map(item=>`<div class="menu-card" data-action="${item.action}"><div class="menu-emoji">${item.emoji}</div><div class="menu-name">${item.name}</div></div>`).join('')}</div></div>`;
    document.querySelectorAll('[data-action]').forEach(card=>{card.onclick=()=>{const s=actions[card.dataset.action];if(s)navigateTo(s)}});
    document.getElementById('homePetWidget').onclick=()=>navigateTo(Screens.PET_MODULE);
    const cb=document.getElementById('chestsBadge');if(cb)cb.onclick=()=>navigateTo(Screens.CHESTS);
    startPetPhrases();
}
function startPetPhrases(){const phrases=['Хочу кушать! 😋','Поиграй со мной! 🎾','Ты лучший! 🥰','Я немного устал... 😴','Давай учиться! 📚','Погладь меня! 🤗','Мне скучно... ☹️'];setInterval(()=>{const b=document.getElementById('homePetBubble');if(b&&Math.random()>0.6){b.textContent=phrases[Math.floor(Math.random()*phrases.length)];b.style.display='block';setTimeout(()=>b.style.display='none',3000)}},20000)}

// ==================== ВЫБОР ПРЕДМЕТА ====================
export function renderSubjectSelection(app) {
    const totals={math:25,russian:23,english:22,world:22};
    const subjects=[{id:'math',emoji:'📐',name:'МАТЕМАТИКА'},{id:'russian',emoji:'📖',name:'РУССКИЙ ЯЗЫК'},{id:'english',emoji:'🇬🇧',name:'АНГЛИЙСКИЙ'},{id:'world',emoji:'🌍',name:'ОКРУЖАЮЩИЙ МИР'}];
    app.innerHTML=`<div class="card"><div class="screen-header"><button class="back-btn" id="backToMainFromSubjectsBtn">↩️ Назад</button><h2>📚 ВЫБЕРИ ПРЕДМЕТ</h2><div></div></div><div class="subject-grid">${subjects.map(s=>{const completed=Object.values((AppState.progress[s.id]?.topics||{})).filter(t=>t.completed).length;const stars=Object.values((AppState.progress[s.id]?.topics||{})).reduce((sum,t)=>sum+(t.stars||0),0);return`<div class="subject-card" data-subject="${s.id}"><div class="subject-emoji">${s.emoji}</div><div class="subject-name">${s.name}</div><div class="subject-progress">${completed}/${totals[s.id]} тем</div><div class="subject-stars">⭐ ${stars}</div></div>`}).join('')}</div><div class="subject-extra"><div class="marathon-card" data-action="marathon"><div class="marathon-emoji">🏃</div><div class="marathon-name">МАРАФОН</div><div class="marathon-desc">Все предметы вперемешку!</div></div></div></div>`;
    document.getElementById('backToMainFromSubjectsBtn').onclick=()=>navigateTo(Screens.MAIN);
    document.querySelectorAll('[data-subject]').forEach(card=>{card.onclick=()=>{AppState.currentSubject=card.dataset.subject;navigateTo(Screens.WORLDS,{subject:card.dataset.subject})}});
    document.querySelector('[data-action="marathon"]').onclick=()=>showNotification('🏃 Марафон скоро появится!','info');
}

// ==================== КАРТА ЖИЗНИ ====================
export function renderLifeMap(app,subject,worldId){const sn={math:'📐 Математика',russian:'📖 Русский язык',english:'🇬🇧 Английский',world:'🌍 Окружающий мир'};const w=AppState.currentWorld||{name:'Карта жизни',icon:'🗺️'};app.innerHTML=`<div class="card life-map-card"><div class="life-map-header"><button class="back-btn" id="backToWorldsBtn">↩️ К мирам</button><div class="stats-bar"><span>🪙 ${AppState.coins}</span><span>✅ ${getCompletedCount(subject)}/${getTotalTopicsCount(subject)}</span></div></div><h2 style="text-align:center;margin:20px 0;">${w.icon} ${w.name}</h2><p style="text-align:center;color:var(--text-secondary);">${sn[subject]} — проходи темы по порядку!</p><div class="classes-container" id="lifeMapContent"><p style="text-align:center;padding:40px;">Загрузка тем...</p></div></div>`;document.getElementById('backToWorldsBtn').onclick=()=>navigateTo(Screens.WORLDS,{subject});loadLifeMapContent(subject)}
async function loadLifeMapContent(subject){const c=document.getElementById('lifeMapContent');try{const r=await fetch(`/data/${subject}-topics.json`);if(r.ok){const d=await r.json();renderTopicsGrid(c,d,subject)}else{c.innerHTML='<p style="text-align:center;">Темы скоро появятся!</p>'}}catch(e){c.innerHTML='<p style="text-align:center;">Загрузка тем...</p>'}}
function renderTopicsGrid(container,data,subject){const progress=AppState.progress[subject]||{topics:{},diplomas:[]};let html='';data.classes.forEach(cls=>{let topicsHtml='<div class="topics-grid">';let prevCompleted=true;cls.topics.forEach(topic=>{const tp=progress.topics[topic.id]||{stars:0,completed:false};const stars='⭐'.repeat(tp.stars)+'☆'.repeat(3-tp.stars);const locked=!prevCompleted;if(tp.completed)prevCompleted=true;else prevCompleted=false;topicsHtml+=`<div class="topic-card ${locked?'locked':''} ${tp.completed?'completed':''}" data-topic-id="${topic.id}"><div class="topic-info"><div class="topic-name">${topic.name}</div><div class="topic-stars">${stars}</div></div><div class="topic-status">${tp.completed?'✅':(locked?'🔒':'📝')}</div></div>`});topicsHtml+='</div>';const completed=cls.topics.filter(t=>progress.topics[t.id]?.completed).length;const hasDiploma=progress.diplomas.some(d=>d.classId===cls.id);html+=`<div class="class-card"><div class="class-title"><span>${cls.name}</span><span class="class-progress">📊 ${completed}/${cls.topics.length}</span>${hasDiploma?'<span class="class-diploma">🎓</span>':''}</div>${topicsHtml}</div>`});container.innerHTML=html;document.querySelectorAll('.topic-card:not(.locked)').forEach(card=>{card.onclick=()=>{const topicId=card.dataset.topicId;for(let cls of data.classes){const topic=cls.topics.find(t=>t.id===topicId);if(topic){topic.subject=subject;AppState.currentTopic=topic;navigateTo(Screens.LEARNING,{topic});break}}}})}
function getCompletedCount(subject){const p=AppState.progress[subject];return p?Object.values(p.topics||{}).filter(t=>t.completed).length:0}
function getTotalTopicsCount(subject){const t={math:25,russian:23,english:22,world:22};return t[subject]||0}

// ==================== ЭКРАН ОБУЧЕНИЯ ====================
export function renderLearningScreen(app,topic){if(!topic){navigateTo(Screens.MAIN);return}import('./task-generator.js').then(module=>{const tasks=module.generateTasks(topic,5);renderLearningContent(app,topic,tasks)})}
function renderLearningContent(app,topic,tasks){let currentTaskIndex=0,correctAnswers=0,lives=3,hintShown=false;app.innerHTML=`<div class="card learning-card"><div class="learning-header"><button class="back-btn" id="backToMapBtn">← К карте</button><div class="lives-display" id="livesDisplay">${'❤️'.repeat(lives)}${'🩶'.repeat(3-lives)}</div><button id="skipTaskBtn" class="btn-small" ${AppState.inventory.skipTokens<=0?'disabled':''}>⏭️ Пропустить (${AppState.inventory.skipTokens})</button></div><div id="learningContent"><div class="story-box"><span class="story-icon">📖</span><span>${topic.story||'Давай изучим эту тему!'}</span></div><div class="rule-box"><span class="rule-icon">📚</span><span>${topic.rule||'Внимательно читай задание!'}</span></div><div class="progress-bar"><div class="progress-fill" id="taskProgress" style="width:0%"></div></div><div class="task-card"><div class="task-header" id="taskHeader"></div><div class="task-text" id="taskText"></div><div class="options" id="taskOptions"></div></div><div id="hintArea" class="hint-area" style="display:none;"></div><div id="explanationBox" class="explanation-box" style="display:none;"></div></div></div>`;document.getElementById('backToMapBtn').onclick=()=>navigateTo(Screens.LIFE_MAP,{subject:topic.subject});document.getElementById('skipTaskBtn').onclick=()=>{if(AppState.inventory.skipTokens>0){AppState.inventory.skipTokens--;currentTaskIndex++;if(currentTaskIndex>=tasks.length)finishTopic(topic,correctAnswers,tasks.length,lives);else showTask(tasks[currentTaskIndex],currentTaskIndex,tasks.length);updateLivesDisplay(lives)}};function showTask(task,index,total){document.getElementById('taskHeader').textContent=`❓ Вопрос ${index+1} из ${total}`;document.getElementById('taskText').textContent=task.text;document.getElementById('taskProgress').style.width=`${(index/total)*100}%`;const optsDiv=document.getElementById('taskOptions');optsDiv.innerHTML='';const correctAnswer=task.answer;let choices=task.options||[correctAnswer];if(!task.options){if(typeof correctAnswer==='number'){let candidates=[correctAnswer+1,correctAnswer-1,correctAnswer+2,correctAnswer-2].filter(v=>v>0&&v!==correctAnswer);while(choices.length<3&&candidates.length)choices.push(candidates.shift());while(choices.length<3)choices.push(choices[0])}else{['круг','квадрат','треугольник','4','3','<','>','=','Да','Нет'].forEach(opt=>{if(opt!==correctAnswer&&!choices.includes(opt)&&choices.length<3)choices.push(opt)})}}choices.sort(()=>Math.random()-0.5);choices.forEach(opt=>{const btn=document.createElement('button');btn.className='option-btn';btn.textContent=opt;btn.onclick=()=>{if(opt==correctAnswer){correctAnswers++;currentTaskIndex++;EventBus.emit('sound:correct');if(currentTaskIndex>=tasks.length)finishTopic(topic,correctAnswers,tasks.length,lives);else{showTask(tasks[currentTaskIndex],currentTaskIndex,tasks.length);showNotification('✅ Правильно!','success')}}else{lives--;updateLivesDisplay(lives);document.getElementById('explanationBox').innerHTML=`❌ Неправильно. Правильный ответ: <strong>${correctAnswer}</strong>`;document.getElementById('explanationBox').style.display='block';EventBus.emit('sound:wrong');if(!AppState.mistakes)AppState.mistakes=[];AppState.mistakes.push({date:new Date().toISOString(),question:task.text,userAnswer:opt.toString(),correctAnswer:correctAnswer.toString()});if(lives<=1&&!hintShown){hintShown=true;document.getElementById('hintArea').innerHTML=`💡 Подсказка: правильный ответ — <strong>${correctAnswer}</strong>`;document.getElementById('hintArea').style.display='block'}if(lives<=0){if(AppState.inventory.reviveTokens>0){AppState.inventory.reviveTokens--;lives=3;updateLivesDisplay(lives);showNotification('♻️ Воскрешён! +3 жизни','success')}else{finishTopic(topic,correctAnswers,tasks.length,0);showNotification('😢 Жизни закончились...','error')}}}};optsDiv.appendChild(btn)})}function updateLivesDisplay(l){document.getElementById('livesDisplay').innerHTML='❤️'.repeat(Math.max(0,l))+'🩶'.repeat(Math.max(0,3-l))}showTask(tasks[0],0,tasks.length)}
function finishTopic(topic,correct,total,lives){const subject=topic.subject||AppState.currentSubject;const progress=AppState.progress[subject]||{topics:{},diplomas:[]};const existing=progress.topics[topic.id]||{stars:0,completed:false};let stars=0;if(lives<=0)stars=0;else if(correct===total)stars=3;else if(correct>=3)stars=2;else if(correct>=1)stars=1;if(!existing.completed&&stars>0){existing.completed=true;existing.stars=Math.max(existing.stars,stars);updateCoins(20);updateSolved(correct);showNotification(`🎉 Тема пройдена! +20🪙, ⭐${stars}`,'success')}else if(existing.completed){existing.stars=Math.max(existing.stars,stars);updateCoins(15);showNotification(`🔄 Повторение! +15🪙`,'success')}else{showNotification('😢 Попробуй ещё раз!','error')}progress.topics[topic.id]=existing;AppState.progress[subject]=progress;saveState(AppState.currentChild?.id);setTimeout(()=>navigateTo(Screens.LIFE_MAP,{subject}),1500)}

// ==================== СУНДУКИ ====================
export function renderChests(app){const chests=AppState.chests;app.innerHTML=`<div class="card"><div class="screen-header"><button class="back-btn" id="backFromChestsBtn">↩️ Назад</button><h2>🎁 Сундуки</h2><div></div></div><div class="chests-container"><div class="chests-info"><p>Доступно: <strong>${chests.available}</strong> | Открыто: <strong>${chests.opened}</strong></p><p style="font-size:0.9rem;color:#888;">💡 Каждые 20 решённых примеров = 3 сундука!</p></div>${chests.available>0?`<div class="chests-to-open">${Array(Math.min(chests.available,3)).fill().map(()=>'<div class="chest-item"><div class="chest-emoji">🪎</div><div class="chest-label">Открыть</div></div>').join('')}</div><button id="openAllChestsBtn">🎁 Открыть все (${chests.available} шт.)</button>`:'<div class="no-chests"><p style="font-size:4rem;">🪎</p><p>Нет доступных сундуков</p><p style="color:#888;">Решай примеры, чтобы получить сундуки!</p></div>'}${chests.history.length>0?`<div class="chests-history"><h3>📜 История</h3><div class="history-list">${chests.history.slice(-10).reverse().map(h=>`<div class="history-item"><span>${h.emoji}</span><span>${h.type==='legendary'?'💎 ЛЕГЕНДА':(h.type==='rare'?'✨ Редкий':'Обычный')}</span><span>+${h.reward} 🪙</span></div>`).join('')}</div></div>`:''}</div></div>`;document.getElementById('backFromChestsBtn').onclick=()=>navigateTo(Screens.MAIN);document.querySelectorAll('.chest-item').forEach(item=>{item.onclick=()=>{const r=openChest();if(r){showChestResult(r);setTimeout(()=>{renderChests(app);saveState(AppState.currentChild?.id)},500)}}});const oa=document.getElementById('openAllChestsBtn');if(oa){oa.onclick=()=>{const count=Math.min(chests.available,5);const results=[];for(let i=0;i<count;i++){const r=openChest();if(r)results.push(r)}if(results.length>0){showChestResults(results);setTimeout(()=>{renderChests(app);saveState(AppState.currentChild?.id)},1000)}}}}
function showChestResult(result){const c=document.getElementById('modal-container');const m=document.createElement('div');m.className='modal-overlay';m.innerHTML=`<div class="chest-result-card ${result.type}"><div class="chest-result-emoji">${result.emoji}</div><div class="chest-result-type">${result.type==='legendary'?'💎 ЛЕГЕНДАРНЫЙ!':(result.type==='rare'?'✨ Редкий!':'Обычный')}</div><div class="chest-result-reward">+${result.reward} 🪙</div><button class="chest-result-btn">🎉 Ура!</button></div>`;c.appendChild(m);m.querySelector('.chest-result-btn').onclick=()=>m.remove();m.addEventListener('click',e=>{if(e.target===m)m.remove()});setTimeout(()=>{if(m.parentNode)m.remove()},3000)}
function showChestResults(results){const c=document.getElementById('modal-container');const total=results.reduce((s,r)=>s+r.reward,0);const hl=results.some(r=>r.type==='legendary');const m=document.createElement('div');m.className='modal-overlay';m.innerHTML=`<div class="chest-result-card ${hl?'legendary':'rare'}"><div class="chest-result-emoji">🪎🪎🪎</div><div class="chest-result-type">Открыто ${results.length} сундуков!</div><div class="chest-results-list">${results.map(r=>`<div>${r.emoji} +${r.reward} 🪙</div>`).join('')}</div><div class="chest-result-reward">Итого: +${total} 🪙</div><button class="chest-result-btn">🎉 Круто!</button></div>`;c.appendChild(m);m.querySelector('.chest-result-btn').onclick=()=>m.remove();m.addEventListener('click',e=>{if(e.target===m)m.remove()})}

// ==================== МАГАЗИН ====================
export function renderShop(app,tab='food'){app.innerHTML=`<div class="card"><div class="screen-header"><button class="back-btn" id="backFromShopBtn">↩️ Назад</button><h2>🛒 Магазин</h2><div class="coins-display">🪙 ${AppState.coins}</div></div><div class="shop-tabs"><div class="shop-tab ${tab==='food'?'active':''}" data-tab="food">🍎 Еда</div><div class="shop-tab ${tab==='accessories'?'active':''}" data-tab="accessories">🎩 Аксессуары</div><div class="shop-tab ${tab==='themes'?'active':''}" data-tab="themes">🎨 Темы</div><div class="shop-tab ${tab==='tokens'?'active':''}" data-tab="tokens">🎫 Токены</div></div><div class="shop-items" id="shopItems"></div><button id="openInventoryBtn" class="btn-secondary" style="margin-top:20px;">📦 Инвентарь</button></div>`;document.getElementById('backFromShopBtn').onclick=()=>navigateTo(Screens.MAIN);document.getElementById('openInventoryBtn').onclick=()=>renderInventory(app);document.querySelectorAll('.shop-tab').forEach(tabEl=>{tabEl.onclick=()=>renderShop(app,tabEl.dataset.tab)});const ic=document.getElementById('shopItems');
if(tab==='food'){const food=[{id:'apple',emoji:'🍎',name:'Яблоко',price:5,desc:'+20 голода'},{id:'cookie',emoji:'🍪',name:'Печенье',price:8,desc:'+15 голода, +5 счастья'},{id:'bone',emoji:'🦴',name:'Косточка',price:10,desc:'+30 голода'},{id:'fish',emoji:'🐟',name:'Рыбка',price:12,desc:'+25 голода'},{id:'cake',emoji:'🎂',name:'Тортик',price:25,desc:'+50 голода, +20 счастья'}];ic.innerHTML=food.map(item=>`<div class="shop-item-card"><div class="shop-item-emoji">${item.emoji}</div><div class="shop-item-name">${item.name}</div><div class="shop-item-desc">${item.desc}</div><div class="shop-item-price">${item.price} 🪙</div><button class="buy-btn">Купить</button></div>`).join('');ic.querySelectorAll('.buy-btn').forEach((btn,i)=>{btn.onclick=()=>{const item=food[i];if(AppState.coins>=item.price){updateCoins(-item.price);const existing=AppState.inventory.food.find(f=>f.id===item.id);if(existing)existing.quantity++;else AppState.inventory.food.push({...item,quantity:1});showNotification(`✅ Куплено: ${item.name}!`,'success');EventBus.emit('shop:itemPurchased');saveState(AppState.currentChild?.id);renderShop(app,tab)}else showNotification('❌ Не хватает монет!','error')}})}
else if(tab==='accessories'){const acc=[{id:'hat_cap',emoji:'🧢',name:'Кепка',price:50},{id:'hat_crown',emoji:'👑',name:'Корона',price:150},{id:'hat_top',emoji:'🎩',name:'Цилиндр',price:100},{id:'glasses',emoji:'👓',name:'Очки',price:35},{id:'scarf',emoji:'🧣',name:'Шарф',price:45},{id:'bow',emoji:'🎀',name:'Бантик',price:30}];ic.innerHTML=acc.map(item=>{const owned=AppState.inventory.accessories.includes(item.id);return`<div class="shop-item-card ${owned?'owned':''}"><div class="shop-item-emoji">${item.emoji}</div><div class="shop-item-name">${item.name}</div><div class="shop-item-price">${owned?'✅ Куплено':item.price+' 🪙'}</div>${!owned?'<button class="buy-btn">Купить</button>':''}</div>`}).join('');ic.querySelectorAll('.buy-btn').forEach((btn,i)=>{btn.onclick=()=>{const item=acc[i];if(!AppState.inventory.accessories.includes(item.id)&&AppState.coins>=item.price){updateCoins(-item.price);AppState.inventory.accessories.push(item.id);showNotification(`✅ Куплено: ${item.name}!`,'success');EventBus.emit('shop:itemPurchased');saveState(AppState.currentChild?.id);renderShop(app,tab)}else showNotification('❌ Не хватает монет!','error')}})}
else if(tab==='themes'){const themes=[{id:'default',name:'☀️ Светлая',price:0},{id:'dark',name:'🌙 Тёмная',price:20},{id:'forest',name:'🌲 Лесная',price:30},{id:'ocean',name:'🌊 Морская',price:35}];ic.innerHTML=themes.map(theme=>{const owned=AppState.inventory.themes.includes(theme.id);const isCurrent=AppState.settings.theme===theme.id;return`<div class="shop-item-card ${owned?'owned':''} ${isCurrent?'current':''}"><div class="shop-item-name">${theme.name}</div><div class="shop-item-price">${owned?(isCurrent?'✅ Текущая':'Куплено'):theme.price+' 🪙'}</div>${owned&&!isCurrent?'<button class="apply-btn">Применить</button>':''}${!owned?'<button class="buy-btn">Купить</button>':''}</div>`}).join('');ic.querySelectorAll('.buy-btn').forEach((btn,i)=>{btn.onclick=()=>{const theme=themes[i];if(!AppState.inventory.themes.includes(theme.id)&&AppState.coins>=theme.price){updateCoins(-theme.price);AppState.inventory.themes.push(theme.id);showNotification(`✅ Куплена тема: ${theme.name}!`,'success');EventBus.emit('shop:itemPurchased');saveState(AppState.currentChild?.id);renderShop(app,tab)}else showNotification('❌ Не хватает монет!','error')}});ic.querySelectorAll('.apply-btn').forEach((btn,i)=>{btn.onclick=()=>{setTheme(themes[i].id);showNotification(`✅ Тема "${themes[i].name}" применена!`,'success');saveState(AppState.currentChild?.id);renderShop(app,tab)}})}
else if(tab==='tokens'){ic.innerHTML=`<div class="shop-item-card"><div class="shop-item-emoji">⏭️</div><div class="shop-item-name">Пропуск задания</div><div class="shop-item-desc">Позволяет пропустить одно задание</div><div class="shop-item-price">50 🪙</div><button class="buy-btn" id="buySkipToken">Купить</button></div><div class="shop-item-card"><div class="shop-item-emoji">♻️</div><div class="shop-item-name">Воскрешение</div><div class="shop-item-desc">Восстанавливает 3 жизни</div><div class="shop-item-price">60 🪙</div><button class="buy-btn" id="buyReviveToken">Купить</button></div>`;document.getElementById('buySkipToken').onclick=()=>{if(AppState.coins>=50){updateCoins(-50);AppState.inventory.skipTokens++;showNotification('✅ Пропуск куплен!','success');EventBus.emit('shop:itemPurchased');saveState(AppState.currentChild?.id);renderShop(app,tab)}else showNotification('❌ Не хватает монет!','error')};document.getElementById('buyReviveToken').onclick=()=>{if(AppState.coins>=60){updateCoins(-60);AppState.inventory.reviveTokens++;showNotification('✅ Воскрешение куплено!','success');EventBus.emit('shop:itemPurchased');saveState(AppState.currentChild?.id);renderShop(app,tab)}else showNotification('❌ Не хватает монет!','error')}}}

// ==================== ИНВЕНТАРЬ ====================
export function renderInventory(app){app.innerHTML=`<div class="card"><div class="screen-header"><button class="back-btn" id="backFromInventoryBtn">↩️ В магазин</button><h2>📦 Инвентарь</h2><div></div></div><div class="inventory-section"><h3>🍎 Еда</h3>${AppState.inventory.food.length>0?`<div class="inventory-grid">${AppState.inventory.food.map(f=>`<div class="inventory-item"><div class="inventory-emoji">${f.emoji}</div><div class="inventory-name">${f.name}</div><div class="inventory-quantity">${f.quantity} шт.</div></div>`).join('')}</div>`:'<p>Нет еды</p>'}</div><div class="inventory-section"><h3>🎩 Аксессуары</h3>${AppState.inventory.accessories.length>0?`<div class="inventory-grid">${AppState.inventory.accessories.map(id=>{const a=[{id:'hat_cap',emoji:'🧢'},{id:'hat_crown',emoji:'👑'},{id:'hat_top',emoji:'🎩'},{id:'glasses',emoji:'👓'},{id:'scarf',emoji:'🧣'},{id:'bow',emoji:'🎀'}].find(x=>x.id===id);return a?`<div class="inventory-item"><div class="inventory-emoji">${a.emoji}</div></div>`:''}).join('')}</div>`:'<p>Нет аксессуаров</p>'}</div><div class="inventory-section"><h3>🎨 Темы</h3><div class="inventory-grid">${AppState.inventory.themes.map(t=>`<div class="inventory-item"><div class="inventory-name">${t}</div></div>`).join('')}</div></div><div class="inventory-section"><h3>🎫 Токены</h3><p>⏭️ Пропуски: ${AppState.inventory.skipTokens}</p><p>♻️ Воскрешения: ${AppState.inventory.reviveTokens}</p></div></div>`;document.getElementById('backFromInventoryBtn').onclick=()=>renderShop(app)}

// ==================== ИГРОТЕКА (ХАБ) ====================
export function renderArcadeHub(app){const allGames=[{id:'maze',name:'🗺️ Лабиринт',emoji:'🗺️',screen:Screens.GAME_MAZE,description:'Найди выход из лабиринта! 5 уровней'},{id:'word',name:'❓ Слово',emoji:'❓',screen:Screens.GAME_WORD,description:'Отгадай слово по буквам! 7 попыток'},{id:'checkers',name:'⚫ Шашки',emoji:'⚫',screen:Screens.GAME_CHECKERS,description:'Классические шашки против бота'},{id:'ticTac',name:'❌ Крестики-нолики',emoji:'❌',screen:Screens.GAME_TIC_TAC,description:'Сыграй против умного бота'},{id:'memory',name:'🧠 Найди пару',emoji:'🧠',screen:Screens.GAME_MEMORY,description:'Тренируй память! 8 пар'},{id:'battleship',name:'🚢 Морской бой',emoji:'🚢',screen:Screens.GAME_BATTLESHIP,description:'Потопи корабли бота!'},{id:'sudoku',name:'🧩 Судоку 4×4',emoji:'🧩',screen:Screens.GAME_SUDOKU,description:'Заполни сетку числами'},{id:'shootGame',name:'🎯 Попади в цель',emoji:'🎯',screen:Screens.GAME_SHOOT,description:'Реши примеры и попади в цель!'},{id:'compareFast',name:'⚡ Сравни числа',emoji:'⚡',screen:Screens.GAME_COMPARE,description:'Сравнивай числа на скорость!'},{id:'fingerCount',name:'🖐️ Счёт на пальцах',emoji:'🖐️',screen:Screens.GAME_FINGER,description:'Посчитай пальцы!'},{id:'numberComposition',name:'🔢 Состав числа',emoji:'🔢',screen:Screens.GAME_COMPOSITION,description:'Разложи число на части'},{id:'clockGame',name:'⏰ Который час?',emoji:'⏰',screen:Screens.GAME_CLOCK,description:'Определи время на часах'},{id:'changeGame',name:'💰 Сдача в магазине',emoji:'💰',screen:Screens.GAME_CHANGE,description:'Посчитай сдачу правильно!'}];const canPlay=AppState.parentControl.enabled?AppState.parentControl.timePlayedToday<AppState.parentControl.dailyTimeLimit:true;app.innerHTML=`<div class="card"><div class="screen-header"><button class="back-btn" id="backFromArcadeBtn">↩️ Назад</button><h2>🎮 ИГРОТЕКА</h2><div></div></div>${!canPlay?`<div class="time-limit-warning"><span>⏰</span><p>Лимит времени на сегодня исчерпан.</p></div>`:''}<p style="text-align:center;margin-bottom:20px;">Всего игр сыграно: <strong>${AppState.totalGames}</strong></p><div class="games-grid">${allGames.map(game=>{const isRestricted=AppState.parentControl.enabled&&AppState.parentControl.restrictedGames.includes(game.id);const locked=!canPlay||isRestricted;return`<div class="game-card ${locked?'locked':''}" data-game-screen="${game.screen}"><div class="game-emoji">${game.emoji}</div><div class="game-name">${game.name}</div><div class="game-desc">${game.description}</div>${locked?'<div class="game-lock">🚫</div>':''}</div>`}).join('')}</div></div>`;document.getElementById('backFromArcadeBtn').onclick=()=>navigateTo(Screens.MAIN);document.querySelectorAll('.game-card:not(.locked)').forEach(card=>{card.onclick=()=>{const s=card.dataset.gameScreen;if(s)navigateTo(s)}})}

// ==================== 13 ЭКРАНОВ ИГР ====================
function gameScreenTemplate(app,title,gameFile,containerId){app.innerHTML=`<div class="card"><div class="screen-header"><button class="back-btn" id="backFrom${containerId}Btn">↩️ Назад</button><h2>${title}</h2><div></div></div><div id="${containerId}"><p style="text-align:center;padding:40px;">Загрузка игры...</p></div></div>`;document.getElementById(`backFrom${containerId}Btn`).onclick=()=>navigateTo(Screens.ARCADE_HUB);import(`../games/${gameFile}.js`).then(m=>{const el=document.getElementById(containerId);if(m.renderScreen)m.renderScreen(el);else if(m.default&&m.default.start)m.default.start();else{el.innerHTML=`<p style="text-align:center;padding:40px;">Игра загружается...</p>`}})}
export const renderMazeScreen=(app)=>gameScreenTemplate(app,'🗺️ Лабиринт','maze','mazeGameContainer');
export const renderWordScreen=(app)=>gameScreenTemplate(app,'❓ Отгадай слово','word','wordGameContainer');
export const renderCheckersScreen=(app)=>gameScreenTemplate(app,'⚫ Шашки','checkers','checkersGameContainer');
export const renderTicTacScreen=(app)=>gameScreenTemplate(app,'❌ Крестики-нолики','tic-tac','ticTacGameContainer');
export const renderMemoryScreen=(app)=>gameScreenTemplate(app,'🧠 Найди пару','memory','memoryGameContainer');
export const renderBattleshipScreen=(app)=>gameScreenTemplate(app,'🚢 Морской бой','battleship','battleshipGameContainer');
export const renderSudokuScreen=(app)=>gameScreenTemplate(app,'🧩 Судоку 4×4','sudoku','sudokuGameContainer');
export const renderShootScreen=(app)=>gameScreenTemplate(app,'🎯 Попади в цель','shoot-game','shootGameContainer');
export const renderCompareScreen=(app)=>gameScreenTemplate(app,'⚡ Сравни числа','compare-fast','compareGameContainer');
export const renderFingerScreen=(app)=>gameScreenTemplate(app,'🖐️ Счёт на пальцах','finger-count','fingerGameContainer');
export const renderCompositionScreen=(app)=>gameScreenTemplate(app,'🔢 Состав числа','number-composition','compositionGameContainer');
export const renderClockScreen=(app)=>gameScreenTemplate(app,'⏰ Который час?','clock-game','clockGameContainer');
export const renderChangeScreen=(app)=>gameScreenTemplate(app,'💰 Сдача в магазине','change-game','changeGameContainer');

// ==================== НАСТРОЙКИ ====================
export function renderSettings(app){app.innerHTML=`<div class="card"><div class="screen-header"><button class="back-btn" id="backFromSettingsBtn">↩️ Назад</button><h2>⚙️ Настройки</h2><div></div></div><h3>🎨 Тема</h3><select id="themeSelect" style="width:100%;padding:15px;border-radius:40px;"><option value="default" ${AppState.settings.theme==='default'?'selected':''}>☀️ Светлая</option><option value="dark" ${AppState.settings.theme==='dark'?'selected':''}>🌙 Тёмная</option><option value="forest" ${AppState.settings.theme==='forest'?'selected':''}>🌲 Лесная</option><option value="ocean" ${AppState.settings.theme==='ocean'?'selected':''}>🌊 Морская</option></select><h3 style="margin-top:20px;">🔊 Звук</h3><label><input type="checkbox" id="soundToggle" ${AppState.settings.soundEnabled?'checked':''}> Звуковые эффекты</label><label><input type="checkbox" id="musicToggle" ${AppState.settings.musicEnabled?'checked':''}> Музыка</label><label><input type="checkbox" id="voiceToggle" ${AppState.settings.voiceEnabled?'checked':''}> Голос робота</label><h3 style="margin-top:20px;">💾 Данные</h3><button id="exportDataBtn">📤 Экспорт</button><button id="importDataBtn" style="margin-top:10px;">📥 Импорт</button><input type="file" id="importFileInput" accept=".json" style="display:none;"><h3 style="margin-top:20px;">🔄 Сброс</h3><button id="resetDataBtn" class="btn-danger">🗑️ Сбросить прогресс</button></div>`;document.getElementById('backFromSettingsBtn').onclick=()=>navigateTo(Screens.MAIN);document.getElementById('themeSelect').onchange=e=>{setTheme(e.target.value);saveState(AppState.currentChild?.id)};document.getElementById('soundToggle').onchange=e=>{AppState.settings.soundEnabled=e.target.checked;saveState(AppState.currentChild?.id)};document.getElementById('musicToggle').onchange=e=>{AppState.settings.musicEnabled=e.target.checked;saveState(AppState.currentChild?.id)};document.getElementById('voiceToggle').onchange=e=>{AppState.settings.voiceEnabled=e.target.checked;saveState(AppState.currentChild?.id)};document.getElementById('exportDataBtn').onclick=()=>exportData(AppState.currentChild?.id);document.getElementById('importDataBtn').onclick=()=>document.getElementById('importFileInput').click();document.getElementById('importFileInput').onchange=e=>{if(e.target.files[0])importData(AppState.currentChild?.id,e.target.files[0])};document.getElementById('resetDataBtn').onclick=()=>{if(confirm('Сбросить весь прогресс?'))resetState(AppState.currentChild?.id)}}

// ==================== ДОСТИЖЕНИЯ ====================
export function renderAchievements(app){const achievements=getAchievements();const unlocked=achievements.filter(a=>a.unlocked).length;app.innerHTML=`<div class="card"><div class="screen-header"><button class="back-btn" id="backFromAchievementsBtn">↩️ Назад</button><h2>🏆 Достижения</h2><div></div></div><p>Разблокировано: <strong>${unlocked}</strong> из <strong>${achievements.length}</strong></p><div class="achievements-grid">${achievements.map(ach=>`<div class="achievement-card ${ach.unlocked?'unlocked':'locked'}"><div class="achievement-icon">${ach.unlocked?'🏆':'🔒'}</div><div class="achievement-name">${ach.name}</div><div class="achievement-desc">${ach.desc}</div><div class="achievement-reward">${ach.unlocked?'✅':`+${ach.reward}🪙`}</div></div>`).join('')}</div></div>`;document.getElementById('backFromAchievementsBtn').onclick=()=>navigateTo(Screens.MAIN)}

// ==================== ПОЛНЫЙ МОДУЛЬ ПИТОМЦА (100%) ====================
export function renderPetModule(app){const pet=AppState.pet||{type:'cat',name:'Мурка',hunger:100,happiness:100,energy:100,isSleeping:false,outfit:{},room:{vaseFlower:'🌻'}};const petEmoji={cat:'🐱',dog:'🐶',rabbit:'🐰',fox:'🦊',koala:'🐨',pig:'🐷'}[pet.type]||'🐱';const room=AppState.petRoom||'bedroom';app.innerHTML=`<div class="pet-module-container"><div class="top-panel"><div class="age-badge"><span>🎂</span><span>${pet.age||0} дн.</span></div><div class="coins-badge"><span>🪙</span><span>${AppState.coins}</span></div></div><div class="room-area room-${room}"><div class="room-background"></div><div class="room-items" id="petRoomItems"></div><div class="plates-container" id="petPlatesContainer" style="display:none;"></div><div class="pet-character pet-type-${pet.type}${pet.isSleeping?' sleeping':''}" id="petCharacter"><span class="pet-base">${petEmoji}</span>${pet.outfit.hat?`<span class="pet-hat">${pet.outfit.hat}</span>`:''}${pet.outfit.glasses?`<span class="pet-glasses">${pet.outfit.glasses}</span>`:''}${pet.outfit.scarf?`<span class="pet-scarf">${pet.outfit.scarf}</span>`:''}${pet.outfit.bow?`<span class="pet-bow">${pet.outfit.bow}</span>`:''}${pet.isSleeping?'<span class="sleeping-zzz">💤</span>':''}</div></div><div class="bottom-panel"><div class="room-tab ${room==='bedroom'?'active':''}" data-room="bedroom"><span class="tab-icon">😴</span><span class="tab-label">Спальня</span><div class="tab-indicator" style="background:conic-gradient(#2196f3 ${pet.energy}%,#ddd ${pet.energy}%)">⚡${pet.energy}%</div></div><div class="room-tab ${room==='kitchen'?'active':''}" data-room="kitchen"><span class="tab-icon">🍴</span><span class="tab-label">Кухня</span><div class="tab-indicator" style="background:conic-gradient(#4caf50 ${pet.hunger}%,#ddd ${pet.hunger}%)">🍖${pet.hunger}%</div></div><div class="room-tab ${room==='living'?'active':''}" data-room="living"><span class="tab-icon">🛋️</span><span class="tab-label">Гостиная</span><div class="tab-indicator" style="background:conic-gradient(#ff9800 ${pet.happiness}%,#ddd ${pet.happiness}%)">😊${pet.happiness}%</div></div><div class="room-tab ${room==='street'?'active':''}" data-room="street"><span class="tab-icon">🏞️</span><span class="tab-label">Улица</span><div class="tab-indicator">🎮</div></div></div><button class="back-button" id="backFromPetRoomBtn">↩️ Назад</button></div>`;
document.getElementById('backFromPetRoomBtn').onclick=()=>navigateTo(Screens.MAIN);
document.querySelectorAll('.room-tab').forEach(tab=>{tab.onclick=()=>{AppState.petRoom=tab.dataset.room;renderPetModule(app)}});
renderPetRoomItems(pet,room);setupPetEvents(pet,room,app)}

function renderPetRoomItems(pet,room){const items=document.getElementById('petRoomItems');const plates=document.getElementById('petPlatesContainer');if(room==='bedroom'){items.innerHTML=`<div class="cozy-window"></div><div class="cozy-picture"></div><div class="cozy-rug"></div><div class="cozy-bed" data-action="sleep"><div class="cozy-pillow"></div></div><div class="cozy-wardrobe" data-action="wardrobe"></div>`;plates.style.display='none'}else if(room==='kitchen'){items.innerHTML=`<div class="cozy-window" style="right:30px;left:auto;"></div><div class="cozy-fridge" data-action="foodShop"></div><div class="cozy-table"></div>`;plates.style.display='flex';renderPetPlates()}else if(room==='living'){items.innerHTML=`<div class="cozy-picture" style="left:20px;"></div><div class="cozy-rug"></div><div class="cozy-sofa" data-action="sofa"><div class="sofa-pillow"></div><div class="sofa-pillow2"></div></div><div class="cozy-tv" data-action="tv"></div><div class="cozy-vase-stand"></div>`;plates.style.display='none';const vaseDiv=document.createElement('div');vaseDiv.className='vase-container';vaseDiv.setAttribute('data-action','vase');vaseDiv.innerHTML=`<span class="vase">⚱️</span><span class="flower-inside">${pet.room?.vaseFlower||'🌻'}</span>`;items.appendChild(vaseDiv)}else if(room==='street'){items.innerHTML=`<div class="item-sun">☀️</div><div class="item-cloud item-cloud1">☁️</div><div class="item-cloud item-cloud2">☁️</div><div class="cozy-fence"></div><div class="cozy-tree"><div class="tree-trunk"></div><div class="tree-crown"></div></div><div class="cozy-chest" data-action="games"></div>`;plates.style.display='none'}}

function renderPetPlates(){const container=document.getElementById('petPlatesContainer');const plates=AppState.petPlates||[{food:'apple',emoji:'🍎',quantity:3},{food:'cookie',emoji:'🍪',quantity:5},{food:null,emoji:'🍽️',quantity:0}];container.innerHTML=plates.map((plate,i)=>`<div class="plate ${plate.food?'':'empty'}" data-plate-index="${i}"><div class="plate-emoji">${plate.emoji}</div>${plate.quantity>0?`<div class="plate-quantity">${plate.quantity}</div>`:''}</div>`).join('');container.querySelectorAll('.plate').forEach((plate,i)=>{plate.draggable=!!plates[i].food;plate.addEventListener('dragstart',e=>{if(!plates[i].food||plates[i].quantity<=0){e.preventDefault();return}e.dataTransfer.setData('text/plain',i.toString())})})}

function setupPetEvents(pet,room,app){const petChar=document.getElementById('petCharacter');petChar.addEventListener('dragover',e=>e.preventDefault());petChar.addEventListener('drop',e=>{e.preventDefault();const idx=e.dataTransfer.getData('text/plain');if(idx==='')return;const plates=AppState.petPlates||[];const plate=plates[parseInt(idx)];if(!plate?.food||plate.quantity<=0)return;const foodMap={apple:{nutrition:20},cookie:{nutrition:15,happiness:5},bone:{nutrition:30},fish:{nutrition:25},cake:{nutrition:50,happiness:20}};const fd=foodMap[plate.food]||{nutrition:15};updatePetHunger(fd.nutrition);if(fd.happiness)updatePetHappiness(fd.happiness);plate.quantity--;if(plate.quantity<=0){plate.food=null;plate.emoji='🍽️'}AppState.petPlates=plates;showNotification(`${pet.name} съел еду! +${fd.nutrition} 🍖`,'success');renderPetPlates();saveState(AppState.currentChild?.id)});petChar.addEventListener('click',e=>{if(e.target.closest('[data-action]'))return;updatePetHappiness(3);showNotification('😊 Мурлычет!','success');saveState(AppState.currentChild?.id)});document.addEventListener('click',e=>{const item=e.target.closest('[data-action]');if(!item)return;const action=item.dataset.action;if(action==='sleep'){if(pet.isSleeping)petWakeUp();else petGoToSleep();showNotification(pet.isSleeping?'😴 Уснул...':'☀️ Проснулся!','success');saveState(AppState.currentChild?.id);setTimeout(()=>renderPetModule(app),300)}else if(action==='wardrobe'){showPetWardrobe()}else if(action==='foodShop'){navigateTo(Screens.SHOP)}else if(action==='tv'){showPetTVGames()}else if(action==='vase'){showPetVaseFlowers(app)}else if(action==='games'){showPetOutdoorGames()}else if(action==='sofa'){updatePetEnergy(10);updatePetHappiness(5);showNotification('🛋️ Отдохнул на диване!','success');saveState(AppState.currentChild?.id)}})}

function showPetWardrobe(){const acc=[{id:'hat_cap',emoji:'🧢',slot:'hat'},{id:'hat_crown',emoji:'👑',slot:'hat'},{id:'hat_top',emoji:'🎩',slot:'hat'},{id:'glasses',emoji:'👓',slot:'glasses'},{id:'scarf',emoji:'🧣',slot:'scarf'},{id:'bow',emoji:'🎀',slot:'bow'}];const owned=acc.filter(a=>AppState.inventory.accessories.includes(a.id));const c=document.getElementById('modal-container');const m=document.createElement('div');m.className='modal-overlay';m.innerHTML=`<div class="modal-card"><h3>🚪 Гардероб</h3>${owned.length>0?`<div style="display:flex;gap:15px;flex-wrap:wrap;justify-content:center;margin:20px 0;">${owned.map(a=>`<div class="wardrobe-item" data-emoji="${a.emoji}" data-slot="${a.slot}" style="font-size:3rem;cursor:pointer;padding:10px;border-radius:15px;background:#ffe0b0;">${a.emoji}</div>`).join('')}</div>`:'<p>Купи аксессуары в магазине!</p>'}<button class="close-btn" id="closeWardrobeBtn">Закрыть</button><button class="btn-danger" id="removeAllBtn" style="margin-top:10px;">🗑️ Снять всё</button></div>`;c.appendChild(m);m.querySelectorAll('.wardrobe-item').forEach(item=>{item.onclick=()=>{const emoji=item.dataset.emoji;const slot=item.dataset.slot;if(!AppState.pet.outfit)AppState.pet.outfit={};if(AppState.pet.outfit[slot]===emoji){AppState.pet.outfit[slot]=null}else{AppState.pet.outfit[slot]=emoji}m.remove();renderPetModule(document.getElementById('app'));showNotification(AppState.pet.outfit[slot]?'Надето!':'Снято!','success');saveState(AppState.currentChild?.id)}});document.getElementById('closeWardrobeBtn').onclick=()=>m.remove();document.getElementById('removeAllBtn').onclick=()=>{AppState.pet.outfit={};m.remove();renderPetModule(document.getElementById('app'));showNotification('Всё снято!','success');saveState(AppState.currentChild?.id)};m.addEventListener('click',e=>{if(e.target===m)m.remove()})}

function showPetTVGames(){const c=document.getElementById('modal-container');const m=document.createElement('div');m.className='modal-overlay';m.innerHTML=`<div class="modal-card"><h3>📺 Видео-игры</h3>${['🏁 Гонки','🎮 Аркада','🎯 Стрелялка'].map((g,i)=>`<div class="game-option" data-game="${['racing','arcadeGame','shooting'][i]}" style="background:#ffe0b0;border-radius:20px;padding:15px;margin:10px 0;cursor:pointer;border:2px solid #d4a259;">${g}</div>`).join('')}<button class="close-btn" id="closeTVBtn">Закрыть</button></div>`;c.appendChild(m);m.querySelectorAll('.game-option').forEach(opt=>{opt.onclick=()=>{const game=opt.dataset.game;m.remove();import(`../games/pet/${game}.js`).then(mod=>{if(mod.default&&mod.default.start)mod.default.start()})}});document.getElementById('closeTVBtn').onclick=()=>m.remove();m.addEventListener('click',e=>{if(e.target===m)m.remove()})}

function showPetOutdoorGames(){const c=document.getElementById('modal-container');const m=document.createElement('div');m.className='modal-overlay';m.innerHTML=`<div class="modal-card"><h3>🎮 Мини-игры</h3>${['🏀 Баскетбол','🎾 Поймай','🦴 Найди косточку'].map((g,i)=>`<div class="game-option" data-game="${['basketball','catch','find'][i]}" style="background:#ffe0b0;border-radius:20px;padding:15px;margin:10px 0;cursor:pointer;border:2px solid #d4a259;">${g}</div>`).join('')}<button class="close-btn" id="closeOutdoorBtn">Закрыть</button></div>`;c.appendChild(m);m.querySelectorAll('.game-option').forEach(opt=>{opt.onclick=()=>{const game=opt.dataset.game;m.remove();import(`../games/pet/${game}.js`).then(mod=>{if(mod.default&&mod.default.start)mod.default.start()})}});document.getElementById('closeOutdoorBtn').onclick=()=>m.remove();m.addEventListener('click',e=>{if(e.target===m)m.remove()})}

function showPetVaseFlowers(app){const flowers=['🌻','🌷','🌹','🌸'];const c=document.getElementById('modal-container');const m=document.createElement('div');m.className='modal-overlay';m.innerHTML=`<div class="modal-card"><h3>⚱️ Выбери цветок</h3><div style="display:flex;gap:15px;justify-content:center;flex-wrap:wrap;margin:20px 0;">${flowers.map(f=>`<div class="flower-option" data-flower="${f}" style="font-size:3rem;cursor:pointer;padding:10px;">${f}</div>`).join('')}</div><button class="close-btn" id="closeVaseBtn">Закрыть</button></div>`;c.appendChild(m);m.querySelectorAll('.flower-option').forEach(opt=>{opt.onclick=()=>{if(!AppState.pet.room)AppState.pet.room={};AppState.pet.room.vaseFlower=opt.dataset.flower;m.remove();renderPetModule(app);showNotification('🌸 Цветок поставлен!','success');saveState(AppState.currentChild?.id)}});document.getElementById('closeVaseBtn').onclick=()=>m.remove();m.addEventListener('click',e=>{if(e.target===m)m.remove()})}

